"use strict";(self.webpackChunk_servicenow_sdk_docs=self.webpackChunk_servicenow_sdk_docs||[]).push([["207726"],{69922(e){e.exports=JSON.parse('{"tag":{"label":"dropdown","permalink":"/sdk/4.9.0/tags/dropdown","allTagsPath":"/sdk/4.9.0/tags","count":4,"items":[{"id":"api/table/columns/choicecolumn-api","title":"ChoiceColumn","description":"Defines a column that restricts input to a predefined set of options rendered as a dropdown, radio buttons, or other selection widget. Use choices to declare the allowed values and defaultValue to set the initial selection.","permalink":"/sdk/4.9.0/api/table/columns/choicecolumn-api"},{"id":"api/choiceset-api","title":"ChoiceSet","description":"Adds choices to a table field by creating a syschoiceset record. Use this API when the field is not owned by the current app \u2014 for example, a globally-defined field on an app-scoped table that extends a global table. For fields owned by the current app, define choices inline in the Table API instead.","permalink":"/sdk/4.9.0/api/choiceset-api"},{"id":"guides/choiceset-guide","title":"ChoiceSet Guide","description":"Guide for adding choices to table fields using the ChoiceSet API. Use this when your app needs to extend choices on a field it does not own \u2014 typically a globally-defined field inherited by an app-scoped table that extends a global table.","permalink":"/sdk/4.9.0/guides/choiceset-guide"},{"id":"api/service-catalog/variables/selectboxvariable-api","title":"SelectBoxVariable","description":"Creates a dropdown select box variable for service catalog forms. Use when users must choose exactly one option from a predefined list. Add a SelectBoxVariable to a CatalogItem or VariableSet via the variables property.","permalink":"/sdk/4.9.0/api/service-catalog/variables/selectboxvariable-api"}],"unlisted":false}}')}}]);